import{_ as e,o as s,c as n,a2 as i}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Aplicacion en backend","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/clean-architecture/04-aplicacion-en-backend.md","filePath":"full-stack/arquitectura/clean-architecture/04-aplicacion-en-backend.md","lastUpdated":1782521464000}'),r={name:"full-stack/arquitectura/clean-architecture/04-aplicacion-en-backend.md"};function o(t,a,l,c,p,d){return s(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="aplicacion-en-backend" tabindex="-1">Aplicacion en backend <a class="header-anchor" href="#aplicacion-en-backend" aria-label="Permalink to &quot;Aplicacion en backend&quot;">​</a></h1><p>Clean Architecture en backend se nota especialmente cuando una API deja de ser una coleccion de controladores con consultas SQL y pasa a expresar casos de uso claros.</p><h2 id="estructura-orientativa" tabindex="-1">Estructura orientativa <a class="header-anchor" href="#estructura-orientativa" aria-label="Permalink to &quot;Estructura orientativa&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/</span></span>
<span class="line"><span>  modules/</span></span>
<span class="line"><span>    orders/</span></span>
<span class="line"><span>      domain/</span></span>
<span class="line"><span>        Order.ts</span></span>
<span class="line"><span>        OrderLine.ts</span></span>
<span class="line"><span>        OrderStatus.ts</span></span>
<span class="line"><span>      application/</span></span>
<span class="line"><span>        CreateOrderUseCase.ts</span></span>
<span class="line"><span>        ConfirmOrderUseCase.ts</span></span>
<span class="line"><span>        OrderRepository.ts</span></span>
<span class="line"><span>      infrastructure/</span></span>
<span class="line"><span>        SqlOrderRepository.ts</span></span>
<span class="line"><span>        OrderMapper.ts</span></span>
<span class="line"><span>      presentation/</span></span>
<span class="line"><span>        OrderController.ts</span></span>
<span class="line"><span>        OrderRoutes.ts</span></span></code></pre></div><p>La estructura puede variar por lenguaje, pero la intencion es la misma: las reglas quedan en el centro y los detalles en los bordes.</p><h2 id="controladores-finos" tabindex="-1">Controladores finos <a class="header-anchor" href="#controladores-finos" aria-label="Permalink to &quot;Controladores finos&quot;">​</a></h2><p>Un controlador no deberia decidir reglas de negocio. Debe leer parametros, validar forma basica, llamar al caso de uso, traducir errores a HTTP y devolver una respuesta.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Controller</span></span>
<span class="line"><span>  parsea request</span></span>
<span class="line"><span>  crea command</span></span>
<span class="line"><span>  ejecuta use case</span></span>
<span class="line"><span>  devuelve status code</span></span></code></pre></div><h2 id="servicios-de-aplicacion" tabindex="-1">Servicios de aplicacion <a class="header-anchor" href="#servicios-de-aplicacion" aria-label="Permalink to &quot;Servicios de aplicacion&quot;">​</a></h2><p>El caso de uso coordina, pero no deberia convertirse en una clase gigante.</p><p>Debe contener:</p><ul><li>Flujo de la operacion.</li><li>Orquestacion entre repositorios y gateways.</li><li>Transacciones cuando aplique.</li><li>Publicacion de eventos de aplicacion.</li></ul><p>No debe contener SQL, serializacion HTTP, detalles de framework ni renderizado de plantillas.</p><h2 id="persistencia" tabindex="-1">Persistencia <a class="header-anchor" href="#persistencia" aria-label="Permalink to &quot;Persistencia&quot;">​</a></h2><p>El repositorio concreto vive en infraestructura.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>application/OrderRepository</span></span>
<span class="line"><span>infrastructure/PostgresOrderRepository</span></span></code></pre></div><p>El mapper evita que el modelo del ORM se filtre hacia el dominio.</p><h2 id="transacciones" tabindex="-1">Transacciones <a class="header-anchor" href="#transacciones" aria-label="Permalink to &quot;Transacciones&quot;">​</a></h2><p>Las transacciones suelen gestionarse en el nivel de aplicacion o infraestructura, no dentro de la entidad.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>transaction {</span></span>
<span class="line"><span>  order = repository.find(id)</span></span>
<span class="line"><span>  order.confirm()</span></span>
<span class="line"><span>  repository.save(order)</span></span>
<span class="line"><span>  eventBus.publish(order.events)</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="frameworks" tabindex="-1">Frameworks <a class="header-anchor" href="#frameworks" aria-label="Permalink to &quot;Frameworks&quot;">​</a></h2><p>En Spring Boot, Django, FastAPI, Laravel, Express o NestJS puedes aplicar la misma idea, aunque cada framework empuje a una estructura concreta.</p><p>La clave es no confundir comodidad del framework con arquitectura del negocio.</p><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>Los controladores no contienen consultas.</li><li>Los casos de uso tienen nombres de accion.</li><li>Los repositorios son contratos claros.</li><li>El dominio no importa clases del framework.</li><li>Los errores se traducen en el borde HTTP.</li></ul>`,25)])])}const b=e(r,[["render",o]]);export{h as __pageData,b as default};
